# WRONG: undefined criterion
annotation_task = {
    "instruction": "Choose the better response.",
    "options": ["A", "B", "Tie"]
}

# RIGHT: explicit, measurable criterion
annotation_task = {
    "instruction": "Choose the response that MORE ACCURATELY answers the question without adding unsupported claims.",
    "rubric": {
        "Choose A": "A is more accurate OR B contains at least one false claim.",
        "Choose B": "B is more accurate OR A contains at least one false claim.",
        "Tie": "Both are equally accurate or both contain the same errors."
    },
    "options": ["A", "B", "Tie"]
}

# Honeypot detection: embed known items to catch inattentive raters
HONEYPOTS = [
    {
        "id": "honeypot_001",
        "prompt": "What is 2+2?",
        "response_a": "4",
        "response_b": "The capital of France is Berlin.",
        "correct_choice": 1,   # A is obviously better
    }
]

def audit_rater_quality(annotations: list[dict], honeypots: list[dict]) -> dict:
    rater_stats = {}
    for ann in annotations:
        rid = ann["rater_id"]
        if rid not in rater_stats:
            rater_stats[rid] = {"total": 0, "honeypot_total": 0, "honeypot_correct": 0,
                                "avg_time_s": [], "flagged": False}
        rater_stats[rid]["total"] += 1
        rater_stats[rid]["avg_time_s"].append(ann.get("time_seconds", 30))
        if ann["item_id"] in {h["id"] for h in honeypots}:
            hp = next(h for h in honeypots if h["id"] == ann["item_id"])
            rater_stats[rid]["honeypot_total"] += 1
            if ann["choice"] == hp["correct_choice"]:
                rater_stats[rid]["honeypot_correct"] += 1

    for rid, s in rater_stats.items():
        avg_time = sum(s["avg_time_s"]) / len(s["avg_time_s"])
        hp_acc = s["honeypot_correct"] / s["honeypot_total"] if s["honeypot_total"] > 0 else None
        if avg_time < 8 or (hp_acc is not None and hp_acc < 0.7):
            rater_stats[rid]["flagged"] = True
    return rater_stats
